 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    let total_x_sum = 0;
    const n = nums.length;

    if (n <= 1) {
        return 0;
    }

    // The minimum required sum of x's is the sum of all positive drops
    // between adjacent elements, as these drops dictate the minimum required 
    // relative increase D[i+1] - D[i] > 0.
    for (let i = 0; i < n - 1; i++) {
